using System; using System.Data; using System.Windows.Forms; using EduNova.Services; using EduNova.WinForms.Helpers;
namespace EduNova.WinForms.Forms.Timetable
{ public partial class frmReplaceTeacherWizard : Form { private readonly TimetableService _svc = new TimetableService(); private readonly TeacherService _teachSvc = new TeacherService(); public frmReplaceTeacherWizard() { InitializeComponent(); Load += frmReplaceTeacherWizard_Load; Theme.StyleDataGridView(dgvPreview); SetupGrid(); } private void SetupGrid() { dgvPreview.Columns.Clear(); dgvPreview.Columns.Add(new DataGridViewTextBoxColumn { Name = "colDay", HeaderText = "Day", Width = 100 }); dgvPreview.Columns.Add(new DataGridViewTextBoxColumn { Name = "colPeriod", HeaderText = "Period", Width = 100 }); dgvPreview.Columns.Add(new DataGridViewTextBoxColumn { Name = "colClass", HeaderText = "Class", Width = 150 }); dgvPreview.Columns.Add(new DataGridViewTextBoxColumn { Name = "colSubject", HeaderText = "Subject", Width = 150 }); dgvPreview.Columns.Add(new DataGridViewTextBoxColumn { Name = "colAction", HeaderText = "Action", Width = 100 }); }
        private void frmReplaceTeacherWizard_Load(object sender, EventArgs e) { try { var t = _teachSvc.GetActive(); cmbOldTeacher.DataSource = t; cmbOldTeacher.DisplayMember = "FullName"; cmbOldTeacher.ValueMember = "TeacherId"; cmbNewTeacher.DataSource = t.Copy(); cmbNewTeacher.DisplayMember = "FullName"; cmbNewTeacher.ValueMember = "TeacherId"; } catch { } }
        private void btnPreview_Click(object sender, EventArgs e) { try { int oldId = (int)cmbOldTeacher.SelectedValue; var dt = _svc.GetReplaceWizardData(oldId); dgvPreview.DataSource = dt; } catch (Exception ex) { MessageBox.Show("Error: " + ex.Message); } }
        private void btnReplace_Click(object sender, EventArgs e) { try { int oldId = (int)cmbOldTeacher.SelectedValue; int newId = (int)cmbNewTeacher.SelectedValue; var dt = _svc.ExecuteReplaceWizard(oldId, newId); dgvPreview.DataSource = dt; MessageBox.Show("Replacement complete!"); } catch (Exception ex) { MessageBox.Show("Error: " + ex.Message); } } } }
